export type DigiCodeCategory = "Messaging" | "Social Media" | "Group Chats" | "Identity & Behaviour" | "Power Moves";
export type DigiCodeTag = "Power" | "Surveillance" | "Identity" | "Sociality" | "Normalisation";
export type DigiCodeSort = "default" | "relatable" | "chaotic" | "violated";

export interface DigiCodeRule {
  id: string;
  article: number;
  articleTitle: string;
  section: string;
  title: string;
  clause: string;
  interpretation: string;
  category: DigiCodeCategory;
  tags: DigiCodeTag[];
  relatableScore: number;
  chaoticScore: number;
  violatedScore: number;
}

export const rules: DigiCodeRule[] = [
  // PART I — FUNDAMENTAL RIGHTS OF DIGITAL CITIZENS
  { id: "1", article: 1, articleTitle: "Fundamental Rights", section: "1", title: "Right to Timely Communication", clause: "Every individual shall have the right to receive a response within a socially acceptable time frame, depending on the relationship and context of communication.", interpretation: "Reply time in digital communication functions as a social signal rather than just a technical delay. The time taken to reply communicates interest, priority, emotional closeness, and power within a relationship.", category: "Messaging", tags: ["Power", "Sociality"], relatableScore: 95, chaoticScore: 40, violatedScore: 90 },
  { id: "2", article: 2, articleTitle: "Fundamental Rights", section: "2", title: "Right to Social Acknowledgment", clause: "Every individual shall have the right to expect acknowledgment from friends and close connections through likes, replies, or responses on important posts and messages.", interpretation: "Likes, comments, and replies function as forms of digital acknowledgment and social validation. Not acknowledging someone's message or post may be interpreted as social neglect or lack of support.", category: "Social Media", tags: ["Sociality", "Normalisation"], relatableScore: 88, chaoticScore: 30, violatedScore: 85 },
  { id: "3", article: 3, articleTitle: "Fundamental Rights", section: "3", title: "Right to Explanation After Being Left on Seen", clause: "If a message is viewed but not replied to for an extended period, the sender shall have the right to seek clarification.", interpretation: "Read receipts convert private reading into visible behaviour. Once message reading becomes visible, not replying is no longer neutral — it becomes a social action that can be interpreted as ignoring, avoidance, or intentional delay.", category: "Messaging", tags: ["Surveillance", "Power"], relatableScore: 92, chaoticScore: 60, violatedScore: 95 },
  { id: "4", article: 4, articleTitle: "Fundamental Rights", section: "4", title: "Right to Digital Inclusion", clause: "Exclusion from Close Friends lists, group chats, or digital circles without valid reason may be considered digital social demotion.", interpretation: "Features like Close Friends lists, group chats, and private stories create visible social hierarchies. Inclusion indicates closeness, trust, and social importance, while exclusion may be interpreted as social distancing or demotion.", category: "Social Media", tags: ["Sociality", "Identity"], relatableScore: 80, chaoticScore: 55, violatedScore: 75 },
  { id: "5", article: 5, articleTitle: "Fundamental Rights", section: "5", title: "Right to Meme Communication", clause: "Every individual shall have the right to communicate using memes, reaction images, and digital symbols as valid forms of expression.", interpretation: "Memes, GIFs, emojis, and reaction images function as a new form of digital language. Meme sharing also functions as social bonding because shared humor indicates shared understanding and cultural belonging.", category: "Group Chats", tags: ["Sociality", "Normalisation"], relatableScore: 85, chaoticScore: 45, violatedScore: 30 },
  { id: "6", article: 6, articleTitle: "Fundamental Rights", section: "6", title: "Right to Identity Management", clause: "Every individual shall have the right to archive, delete, or edit past content that no longer represents their current identity.", interpretation: "Digital platforms allow individuals to construct, edit, and modify their identity over time. Social media profiles function as controlled identity presentations rather than complete representations of reality.", category: "Identity & Behaviour", tags: ["Identity", "Normalisation"], relatableScore: 78, chaoticScore: 35, violatedScore: 40 },
  { id: "7", article: 7, articleTitle: "Fundamental Rights", section: "7", title: "Right to Communication Consistency", clause: "Individuals shall have the right to expect consistency in communication behaviour. Sudden changes in communication patterns may require explanation.", interpretation: "Consistency in communication creates stability and trust. Sudden changes in reply time, tone, or interaction patterns are often interpreted as emotional change, conflict, loss of interest, or relationship problems.", category: "Messaging", tags: ["Sociality", "Power"], relatableScore: 90, chaoticScore: 50, violatedScore: 80 },
  { id: "8", article: 8, articleTitle: "Fundamental Rights", section: "8", title: "Right to Digital Respect", clause: "Ignoring important messages, repeated dry replies, or lack of acknowledgment may be considered a violation of digital respect.", interpretation: "Digital respect is shown through replying properly, acknowledging messages, and not sending dry replies in serious conversations. Communication style affects relationships and emotional perception.", category: "Messaging", tags: ["Sociality", "Normalisation"], relatableScore: 93, chaoticScore: 45, violatedScore: 88 },

  // PART II — FUNDAMENTAL DUTIES OF DIGITAL CITIZENS
  { id: "9", article: 9, articleTitle: "Fundamental Duties", section: "9", title: "Duty of Acknowledgment", clause: "Individuals shall acknowledge important messages, posts, and communication from close contacts within a reasonable time.", interpretation: "Acknowledgment in digital communication functions as a basic form of social recognition. Ignoring communication is rarely interpreted as neutral; instead, it may be interpreted as neglect, disinterest, or emotional distance.", category: "Messaging", tags: ["Sociality", "Normalisation"], relatableScore: 87, chaoticScore: 30, violatedScore: 82 },
  { id: "10", article: 10, articleTitle: "Fundamental Duties", section: "10", title: "Duty of Engagement", clause: "Close friends shall engage with important posts through likes, comments, or messages.", interpretation: "Engagement such as liking, commenting, and sharing functions as visible support. Lack of engagement may be interpreted as silent disapproval, jealousy, or distance. Engagement is not only interaction but also a public performance of relationships.", category: "Social Media", tags: ["Sociality", "Normalisation"], relatableScore: 86, chaoticScore: 35, violatedScore: 80 },
  { id: "11", article: 11, articleTitle: "Fundamental Duties", section: "11", title: "Duty of Participation in Group Communication", clause: "Individuals shall participate in group chats through replies, reactions, or acknowledgment when addressed.", interpretation: "Group chats function like small digital communities where participation indicates membership and belonging. When individuals repeatedly do not respond, it may be interpreted as disinterest or social withdrawal.", category: "Group Chats", tags: ["Sociality", "Normalisation"], relatableScore: 82, chaoticScore: 40, violatedScore: 70 },
  { id: "12", article: 12, articleTitle: "Fundamental Duties", section: "12", title: "Duty of Public Acknowledgment", clause: "Close friends shall acknowledge birthdays, achievements, and major life events publicly where socially expected.", interpretation: "Public acknowledgment, such as birthday stories or congratulatory posts, is a performative act that displays relationships publicly. Digital platforms turn private relationships into public performances.", category: "Social Media", tags: ["Sociality", "Identity"], relatableScore: 84, chaoticScore: 30, violatedScore: 78 },
  { id: "13", article: 13, articleTitle: "Fundamental Duties", section: "13", title: "Duty of Communication Responsibility", clause: "Individuals shall respond to emotionally important messages with appropriate tone and seriousness.", interpretation: "In digital communication, tone must be communicated through text, emojis, and response style. Responding casually to serious messages may be interpreted as emotional insensitivity or lack of care.", category: "Messaging", tags: ["Sociality", "Normalisation"], relatableScore: 89, chaoticScore: 40, violatedScore: 75 },
  { id: "14", article: 14, articleTitle: "Fundamental Duties", section: "14", title: "Duty of Digital Courtesy", clause: "Individuals shall inform before leaving groups, cancelling plans, or ending conversations abruptly.", interpretation: "Digital actions such as leaving a group or ending a conversation are not just technical actions but social actions with social meaning. Traditional social etiquette and politeness continue to exist in digital environments.", category: "Group Chats", tags: ["Sociality", "Normalisation"], relatableScore: 80, chaoticScore: 50, violatedScore: 72 },
  { id: "15", article: 15, articleTitle: "Fundamental Duties", section: "15", title: "Duty of Response to Direct Communication", clause: "Direct communication such as reels, memes, tagged posts, or personal messages shall be acknowledged.", interpretation: "Sending reels, memes, or tagged posts is a form of interaction and an attempt to maintain communication. Ignoring direct communication may be interpreted as lack of interest or effort.", category: "Messaging", tags: ["Sociality", "Normalisation"], relatableScore: 88, chaoticScore: 35, violatedScore: 80 },

  // CHAPTER 1 — MESSAGING CODE
  { id: "16", article: 16, articleTitle: "Messaging Code", section: "16", title: "Reply Time Regulation", clause: "Reply time shall be proportional to the closeness of the relationship and the seriousness of the conversation. Immediate replies may be interpreted as high interest, urgency, or excessive availability. Consistently delayed replies may be interpreted as low priority, disinterest, or intentional distancing.", interpretation: "Reply time functions as a form of non-verbal communication. The speed of response communicates emotional closeness, interest, priority, and availability. Delayed replies may be used strategically to manage social value and control emotional distance.", category: "Messaging", tags: ["Power", "Sociality"], relatableScore: 96, chaoticScore: 55, violatedScore: 92 },
  { id: "17", article: 17, articleTitle: "Messaging Code", section: "17", title: "Double Text Regulation", clause: "Sending multiple messages without receiving a reply may be interpreted as urgency, emotional investment, desperation, or impatience. Excessive double texting without reasonable cause may reduce perceived social power in conversation.", interpretation: "Double texting indicates emotional urgency or investment in the conversation. The person who double texts often appears more emotionally invested, which may shift the power balance in the interaction.", category: "Messaging", tags: ["Power", "Sociality"], relatableScore: 94, chaoticScore: 70, violatedScore: 93 },
  { id: "18", article: 18, articleTitle: "Messaging Code", section: "18", title: "Seen Receipt Protocol", clause: "Viewing a message without replying shall be considered a social action and not a neutral action. Repeatedly viewing messages without replying may be interpreted as avoidance, disinterest, or intentional ignoring.", interpretation: "Read receipts transform message reading into visible behaviour. Once a message is marked as 'seen,' not replying becomes socially meaningful. This feature creates pressure to respond and turns silence into a communicative act.", category: "Messaging", tags: ["Surveillance", "Power"], relatableScore: 97, chaoticScore: 65, violatedScore: 96 },
  { id: "19", article: 19, articleTitle: "Messaging Code", section: "19", title: "Typing Indicator Regulation", clause: "The appearance of the typing indicator shall create expectation of an incoming message. Typing and not sending a message may be interpreted as hesitation, reconsideration, or withdrawal of communication.", interpretation: "The typing indicator creates anticipation and expectation. When typing appears and disappears without a message being sent, it creates uncertainty and overthinking.", category: "Messaging", tags: ["Surveillance", "Sociality"], relatableScore: 91, chaoticScore: 75, violatedScore: 60 },
  { id: "20", article: 20, articleTitle: "Messaging Code", section: "20", title: "Dry Reply Regulation", clause: "Short replies such as 'ok', 'hmm', 'k', 'cool', and similar responses may be interpreted as disinterest, low engagement, or conversation closure. Sending dry replies to long or emotional messages shall be considered a violation of digital communication etiquette.", interpretation: "Dry replies function as indirect communication signals that may indicate disinterest, annoyance, or intention to end the conversation. Tone and message style communicate meaning beyond the literal words.", category: "Messaging", tags: ["Power", "Sociality"], relatableScore: 95, chaoticScore: 60, violatedScore: 91 },
  { id: "21", article: 21, articleTitle: "Messaging Code", section: "21", title: "Message Effort Regulation", clause: "The effort of reply shall be proportional to the effort of the message received. Replying to a long message with a very short response may be interpreted as imbalance in emotional or conversational effort.", interpretation: "Effort in communication — such as message length, detail, and response quality — signals emotional investment and relationship importance. When effort is not reciprocated, it creates perceived imbalance.", category: "Messaging", tags: ["Sociality", "Normalisation"], relatableScore: 90, chaoticScore: 45, violatedScore: 85 },
  { id: "22", article: 22, articleTitle: "Messaging Code", section: "22", title: "Online Status Regulation", clause: "Being online and not replying to messages may be interpreted as intentional ignoring. Claiming to be busy while showing repeated online activity may be considered invalid justification.", interpretation: "Online status makes presence visible, which creates the expectation of response. When someone is online but does not reply, the delay is interpreted as intentional rather than accidental.", category: "Messaging", tags: ["Surveillance", "Power"], relatableScore: 93, chaoticScore: 70, violatedScore: 90 },
  { id: "23", article: 23, articleTitle: "Messaging Code", section: "23", title: "Voice Note Regulation", clause: "Voice notes shall be used for emotional, complex, or detailed communication. Excessively long voice notes may be considered inconvenient communication. Ignoring voice notes shall be interpreted as disrespectful communication behaviour.", interpretation: "Voice notes introduce tone, emotion, and personality into digital communication, making them more personal than text messages. However, long voice notes may require more effort from the receiver.", category: "Messaging", tags: ["Sociality", "Normalisation"], relatableScore: 82, chaoticScore: 50, violatedScore: 65 },
  { id: "24", article: 24, articleTitle: "Messaging Code", section: "24", title: "Emoji Reply Rule", clause: "Emoji replies may function as acknowledgment without continuation of conversation. Certain emojis, including but not limited to '👍', may be interpreted as conversation closure. Emoji-only replies in formal or serious conversations shall be considered inappropriate.", interpretation: "Emoji replies function as acknowledgment without continuing the conversation. Certain emojis, such as the thumbs-up, may signal conversation closure. Emojis can function as complete messages and can control whether a conversation continues or ends.", category: "Messaging", tags: ["Sociality", "Power"], relatableScore: 88, chaoticScore: 55, violatedScore: 78 },
  { id: "25", article: 25, articleTitle: "Messaging Code", section: "25", title: "Late Night Communication Rule", clause: "Messages sent late at night shall be interpreted as more emotional, honest, personal, or serious in nature. Important confessions and emotionally significant conversations are more likely to occur during late-night communication hours.", interpretation: "Time influences communication behaviour. Late-night conversations are often associated with emotional openness, honesty, and personal discussions. Digital communication is influenced not only by what is said but also by when it is said.", category: "Messaging", tags: ["Sociality", "Identity"], relatableScore: 91, chaoticScore: 65, violatedScore: 70 },
  { id: "26", article: 26, articleTitle: "Messaging Code", section: "26", title: "Message Editing Regulation", clause: "Editing a message after sending may be interpreted as reconsideration of wording, tone, or meaning. Frequent message editing may be interpreted as concern about how the message is perceived.", interpretation: "Editing messages shows that individuals actively manage how they are perceived in communication. It reflects self-presentation and concern about interpretation.", category: "Messaging", tags: ["Identity", "Normalisation"], relatableScore: 83, chaoticScore: 45, violatedScore: 50 },
  { id: "27", article: 27, articleTitle: "Messaging Code", section: "27", title: "Conversation Power Regulation", clause: "The individual who replies less frequently, with shorter messages, or with delayed timing may be perceived as holding greater conversational power. The individual who replies quickly, sends longer messages, or double texts may be perceived as holding lower conversational control.", interpretation: "Power in digital communication is often controlled through response timing, message length, and conversational effort. The person who appears less available or less emotionally invested often holds more control.", category: "Power Moves", tags: ["Power", "Sociality"], relatableScore: 92, chaoticScore: 60, violatedScore: 85 },

  // CHAPTER 2 — INSTAGRAM CODE
  { id: "28", article: 28, articleTitle: "Instagram Code", section: "28", title: "Like Regulation", clause: "Liking a post shall constitute the minimum acceptable form of digital acknowledgment. Failure to like a close associate's post while remaining active on the platform may be interpreted as social distancing, disapproval, or lack of support.", interpretation: "Likes function as the most basic form of digital acknowledgment and social support. Since likes are visible and countable, they become part of the attention economy where interaction is measured and compared.", category: "Social Media", tags: ["Sociality", "Normalisation"], relatableScore: 90, chaoticScore: 35, violatedScore: 85 },
  { id: "29", article: 29, articleTitle: "Instagram Code", section: "29", title: "Comment Hierarchy Regulation", clause: "Commenting on a post shall constitute a higher level of social engagement than liking. Generic comments such as 'nice', 'cool', or 'wow' shall be considered low-effort engagement. Personalized or detailed comments shall indicate higher relationship closeness.", interpretation: "Comments require more effort than likes and therefore signal stronger engagement. The type of comment matters — generic comments show low effort, while personalized comments show emotional investment.", category: "Social Media", tags: ["Sociality", "Power"], relatableScore: 84, chaoticScore: 30, violatedScore: 70 },
  { id: "30", article: 30, articleTitle: "Instagram Code", section: "30", title: "Story Interaction Regulation", clause: "Replying to a story shall be considered an indirect method of initiating communication. Repeated story viewing without interaction may be interpreted as passive interest or silent observation.", interpretation: "Story replies function as a low-risk way to start conversation. Viewing stories without replying is a form of passive interaction, where individuals observe others without directly communicating.", category: "Social Media", tags: ["Surveillance", "Sociality"], relatableScore: 89, chaoticScore: 50, violatedScore: 65 },
  { id: "31", article: 31, articleTitle: "Instagram Code", section: "31", title: "Close Friends List Regulation", clause: "The Close Friends list shall represent a restricted digital social circle. Inclusion shall indicate trust, closeness, and higher social ranking. Removal may be interpreted as social distancing or relationship change.", interpretation: "The Close Friends feature allows users to control who sees certain content, creating a visible inner circle. Being added or removed signals changes in trust, closeness, or social ranking.", category: "Social Media", tags: ["Identity", "Sociality"], relatableScore: 87, chaoticScore: 55, violatedScore: 75 },
  { id: "32", article: 32, articleTitle: "Instagram Code", section: "32", title: "Archive and Delete Regulation", clause: "Archiving posts shall be interpreted as aesthetic change, identity modification, or emotional transition. Mass archiving or deletion shall be interpreted as a major identity reset or life transition.", interpretation: "Archiving and deleting posts show that digital identity is curated and changeable. People remove content that no longer fits their current identity or life situation.", category: "Social Media", tags: ["Identity", "Normalisation"], relatableScore: 82, chaoticScore: 60, violatedScore: 55 },
  { id: "33", article: 33, articleTitle: "Instagram Code", section: "33", title: "Caption and Text Regulation", clause: "Captions shall function as tools for context, emotional expression, or indirect communication. Quotes and lyrics may function as indirect communication directed toward specific individuals.", interpretation: "Captions function as a way to add meaning, emotion, or indirect messages to posts. Digital communication often relies on symbolic and indirect expression rather than direct communication.", category: "Social Media", tags: ["Identity", "Sociality"], relatableScore: 80, chaoticScore: 45, violatedScore: 50 },
  { id: "34", article: 34, articleTitle: "Instagram Code", section: "34", title: "Highlight Regulation", clause: "Highlights shall function as permanent digital memory displays. Featuring an individual in highlights shall indicate long-term importance. Removal of an individual from highlights may be interpreted as relationship change.", interpretation: "Highlights function as permanent displays of memories and relationships. Users curate not only their present identity but also their past memories and relationships.", category: "Social Media", tags: ["Identity", "Sociality"], relatableScore: 78, chaoticScore: 50, violatedScore: 60 },
  { id: "35", article: 35, articleTitle: "Instagram Code", section: "35", title: "Posting Frequency Regulation", clause: "Posting frequency shall influence digital visibility and perceived social presence. Excessive posting may be interpreted as attention-seeking behaviour. Very limited posting may be interpreted as privacy preference or intentional identity curation.", interpretation: "Posting frequency affects how visible a person is online and how their identity is perceived. Identity in digital spaces is shaped not only by what is posted but also by how often one posts.", category: "Social Media", tags: ["Identity", "Normalisation"], relatableScore: 83, chaoticScore: 40, violatedScore: 55 },
  { id: "36", article: 36, articleTitle: "Instagram Code", section: "36", title: "Birthday Acknowledgment Regulation", clause: "Public birthday stories shall function as displays of social acknowledgment and relationship value. Failure to acknowledge a close associate's birthday publicly may be interpreted as social distance.", interpretation: "Birthday posts are public displays of friendship and social bonds. Digital platforms turn personal events into public performances of relationships and social connections.", category: "Social Media", tags: ["Sociality", "Normalisation"], relatableScore: 86, chaoticScore: 35, violatedScore: 80 },
  { id: "37", article: 37, articleTitle: "Instagram Code", section: "37", title: "Tagging Regulation", clause: "Tagging an individual in a post shall constitute public acknowledgment of association. Untagging or removing tags may be interpreted as relationship change or distancing.", interpretation: "Tagging someone publicly connects their identity to a post and signals association. Tagging functions as a public display of social connections and relationships.", category: "Social Media", tags: ["Identity", "Sociality"], relatableScore: 79, chaoticScore: 45, violatedScore: 65 },

  // CHAPTER 3 — GROUP CHAT CODE
  { id: "38", article: 38, articleTitle: "Group Chat Code", section: "38", title: "Silent Audience Principle", clause: "In group communication spaces, not all members are required to actively reply to every message. Passive participation through reading messages without replying shall be considered normal group behaviour.", interpretation: "Participation follows an inequality pattern where a small number of members actively contribute while many others passively observe. Lurking is normalized in digital culture.", category: "Group Chats", tags: ["Sociality", "Normalisation"], relatableScore: 90, chaoticScore: 25, violatedScore: 45 },
  { id: "39", article: 39, articleTitle: "Group Chat Code", section: "39", title: "One-to-One Conversation Shift Rule", clause: "When two individuals dominate a group conversation for an extended period, they shall move the conversation to private chat. Continued personal conversation in a group chat may be considered disruptive.", interpretation: "Group chats are collective communication spaces. When two individuals dominate, it shifts the space from public to private communication. Digital spaces have unwritten etiquette rules.", category: "Group Chats", tags: ["Sociality", "Normalisation"], relatableScore: 88, chaoticScore: 50, violatedScore: 75 },
  { id: "40", article: 40, articleTitle: "Group Chat Code", section: "40", title: "Meme Revival Regulation", clause: "Meme sharing shall be considered a valid form of social participation in group communication. Memes may be used to revive inactive group conversations.", interpretation: "Memes function as low-effort but high-impact communication tools that can restart inactive conversations and maintain group interaction. Not all communication is informational — much exists to maintain social presence.", category: "Group Chats", tags: ["Sociality", "Normalisation"], relatableScore: 87, chaoticScore: 45, violatedScore: 30 },
  { id: "41", article: 41, articleTitle: "Group Chat Code", section: "41", title: "Group Exit Protocol", clause: "Any individual who exits a group without prior notice shall be considered to have made a public social statement. Group exit may be interpreted as conflict, disinterest, or social distancing. Rejoining after leaving may require explanation.", interpretation: "Leaving a group chat is a visible action and becomes a public social signal. Because the action is visible to all members, it is interpreted socially as conflict, disinterest, or distancing.", category: "Group Chats", tags: ["Sociality", "Power"], relatableScore: 85, chaoticScore: 75, violatedScore: 70 },
  { id: "42", article: 42, articleTitle: "Group Chat Code", section: "42", title: "Reaction Emoji Regulation", clause: "Reaction emojis shall function as acknowledgment without full participation. Reaction emojis may replace text replies in low-effort communication situations.", interpretation: "Reaction emojis function as minimal participation tools that allow individuals to acknowledge messages without fully engaging. Digital communication allows different levels of participation.", category: "Group Chats", tags: ["Sociality", "Normalisation"], relatableScore: 84, chaoticScore: 30, violatedScore: 35 },
  { id: "43", article: 43, articleTitle: "Group Chat Code", section: "43", title: "Groupchat Tagging Regulation", clause: "Tagging specific individuals in group chats shall indicate targeted communication. Sudden absence of tagging where tagging was previously frequent may be interpreted as social distance.", interpretation: "Tagging allows communication to be directed at specific individuals within a group, creating sub-groups and inside jokes. Frequent tagging between individuals indicates closeness.", category: "Group Chats", tags: ["Sociality", "Identity"], relatableScore: 78, chaoticScore: 40, violatedScore: 55 },
  { id: "44", article: 44, articleTitle: "Group Chat Code", section: "44", title: "The Ignored Message Effect", clause: "Messages sent in group chats may be ignored even when viewed by multiple members. Being ignored in a group chat may be perceived as social exclusion and is louder than being argued with.", interpretation: "Being ignored in a group chat can create feelings of exclusion because communication is visible. Absence of response can communicate as strongly as a direct response.", category: "Group Chats", tags: ["Power", "Sociality"], relatableScore: 92, chaoticScore: 65, violatedScore: 88 },
  { id: "45", article: 45, articleTitle: "Group Chat Code", section: "45", title: "Group Energy Leadership Rule", clause: "Certain members who frequently send messages, memes, or updates shall function as informal leaders of group interaction. Absence of such members may lead to group inactivity.", interpretation: "Certain members play key roles in maintaining group interaction by sending messages, memes, or updates. Even in informal digital groups, social roles and leadership structures naturally develop.", category: "Group Chats", tags: ["Power", "Sociality"], relatableScore: 86, chaoticScore: 40, violatedScore: 50 },
  { id: "46", article: 46, articleTitle: "Group Chat Code", section: "46", title: "Message Flood Regulation", clause: "Sending multiple consecutive messages within a short period may be considered message flooding. Message flooding may result in important information being ignored or missed.", interpretation: "Sending many messages in a short time creates information overload, causing important messages to be ignored or missed. Attention in digital spaces is limited.", category: "Group Chats", tags: ["Sociality", "Normalisation"], relatableScore: 83, chaoticScore: 70, violatedScore: 65 },
  { id: "47", article: 47, articleTitle: "Group Chat Code", section: "47", title: "Important Message Acknowledgment Rule", clause: "Important messages in group chats shall be acknowledged by relevant members. If important information is ignored, the sender may repeat the message.", interpretation: "Acknowledging important messages ensures that communication is successful and understood. Failure to acknowledge may lead to miscommunication.", category: "Group Chats", tags: ["Sociality", "Normalisation"], relatableScore: 81, chaoticScore: 35, violatedScore: 72 },
  { id: "48", article: 48, articleTitle: "Group Chat Code", section: "48", title: "Screenshot Regulation", clause: "Messages sent in group chats shall be considered permanent and shareable. Individuals shall assume that any message sent in a group may become public.", interpretation: "The ability to screenshot messages makes digital communication permanent and shareable beyond the original context. This creates a culture of surveillance where individuals must assume anything can be saved and shared.", category: "Group Chats", tags: ["Surveillance", "Power"], relatableScore: 88, chaoticScore: 80, violatedScore: 75 },
  { id: "49", article: 49, articleTitle: "Group Chat Code", section: "49", title: "Administrative Power Rule", clause: "Group administrators shall hold administrative authority, including adding and removing members. Removal of a member shall be interpreted as a strong social action. Administrative power shall be exercised responsibly.", interpretation: "Group administrators hold structural power. Administrative actions, such as removing a member, are not just technical actions but social actions that affect relationships and group dynamics.", category: "Group Chats", tags: ["Power", "Sociality"], relatableScore: 80, chaoticScore: 65, violatedScore: 60 },

  // CHAPTER 4 — RELATIONSHIP CODE
  { id: "50", article: 50, articleTitle: "Relationship Code", section: "50", title: "Reply Time Variation Regulation", clause: "Reply time behaviour in relationships shall be governed by Article 16, and variations in reply time may be interpreted as changes in emotional priority or relationship dynamics.", interpretation: "Reply time is not interpreted equally for all people; individuals reply faster to emotionally important people. Changes in reply time behaviour are often interpreted as changes in feelings or relationship dynamics.", category: "Identity & Behaviour", tags: ["Power", "Sociality"], relatableScore: 91, chaoticScore: 55, violatedScore: 82 },
  { id: "51", article: 51, articleTitle: "Relationship Code", section: "51", title: "Visibility and Trust Regulation", clause: "Visibility indicators such as last seen and online status shall influence trust within digital relationships. Inconsistency between visible activity and communication behaviour may lead to suspicion or emotional tension.", interpretation: "Features such as last seen and online status create visibility. If someone appears online but does not respond, it may create suspicion or emotional tension. Platform visibility features influence emotional relationships.", category: "Identity & Behaviour", tags: ["Surveillance", "Sociality"], relatableScore: 90, chaoticScore: 65, violatedScore: 85 },
  { id: "52", article: 52, articleTitle: "Relationship Code", section: "52", title: "Soft Launch Regulation", clause: "A soft launch shall refer to indirectly introducing a relationship without revealing full identity of the person. Soft launches may be used to observe audience reaction before public confirmation.", interpretation: "A soft launch allows individuals to introduce a relationship gradually. Relationships are strategically presented to an audience, showing that social media involves performance and audience management.", category: "Identity & Behaviour", tags: ["Identity", "Sociality"], relatableScore: 85, chaoticScore: 55, violatedScore: 45 },
  { id: "53", article: 53, articleTitle: "Relationship Code", section: "53", title: "Hard Launch Regulation", clause: "A hard launch shall refer to public confirmation of a relationship through clear identification of the person. Hard launches shall function as official digital acknowledgment of a relationship.", interpretation: "A hard launch is a public confirmation and functions as digital acknowledgment. Posting a partner publicly is not just sharing information but publicly validating the relationship.", category: "Identity & Behaviour", tags: ["Identity", "Sociality"], relatableScore: 83, chaoticScore: 45, violatedScore: 40 },
  { id: "54", article: 54, articleTitle: "Relationship Code", section: "54", title: "Public Display and Visibility Regulation", clause: "Posting an individual on a story shall indicate temporary display. Posting on the feed shall indicate long-term importance. Adding to highlights shall indicate relationship significance. Sudden changes in posting behaviour may be interpreted as a change in relationship status.", interpretation: "Different platform features represent different levels of visibility. Platform features are used strategically to control relationship visibility and public identity.", category: "Identity & Behaviour", tags: ["Identity", "Power"], relatableScore: 84, chaoticScore: 50, violatedScore: 60 },
  { id: "55", article: 55, articleTitle: "Relationship Code", section: "55", title: "Relationship Validation and Separation Regulation", clause: "Public posting, tagging, and highlighting shall function as digital relationship validation. Removal of posts, untagging, deleting shared content, unfollowing, or removing from followers shall be interpreted as indicators of relationship termination.", interpretation: "Posting, tagging, and highlighting someone functions as digital relationship validation, while deleting posts, untagging, or unfollowing signals relationship separation.", category: "Identity & Behaviour", tags: ["Identity", "Sociality"], relatableScore: 86, chaoticScore: 65, violatedScore: 70 },
  { id: "56", article: 56, articleTitle: "Relationship Code", section: "56", title: "Indirect Communication Regulation", clause: "Song lyrics, quotes, captions, and indirect posts may be used to communicate emotions without direct conversation. Such posts may be directed at specific individuals while visible to a wider audience.", interpretation: "Digital platforms allow people to communicate indirectly through captions, songs, quotes, and posts. Digital communication often involves indirect and symbolic communication rather than direct conversation.", category: "Identity & Behaviour", tags: ["Identity", "Sociality"], relatableScore: 87, chaoticScore: 55, violatedScore: 55 },
  { id: "57", article: 57, articleTitle: "Relationship Code", section: "57", title: "Deleted Message Regulation", clause: "The notification 'This message was deleted' shall create curiosity and overthinking. Deleting a message shall not remove the social meaning associated with the message.", interpretation: "When a message is deleted, the platform shows that a message existed but was removed. This creates curiosity and overthinking. Platform features themselves create emotional reactions.", category: "Identity & Behaviour", tags: ["Surveillance", "Sociality"], relatableScore: 93, chaoticScore: 75, violatedScore: 60 },
  { id: "58", article: 58, articleTitle: "Relationship Code", section: "58", title: "Birthday Effort Regulation", clause: "Public birthday posts shall function as displays of social closeness. The effort and personalization of birthday posts shall indicate relationship closeness. High-effort birthday posts shall indicate strong social bonding.", interpretation: "Birthday posts are public performances of friendship and relationship closeness. Digital platforms turn private relationships into public displays that can be seen and judged by others.", category: "Identity & Behaviour", tags: ["Sociality", "Normalisation"], relatableScore: 82, chaoticScore: 30, violatedScore: 72 },

  // CHAPTER 5 — CONFLICT CODE
  { id: "59", article: 59, articleTitle: "Conflict Code", section: "59", title: "Unfollow Regulation", clause: "Any individual who unfollows another shall be considered to have made a public signal of distancing, conflict, or relationship change. Mutual unfollowing shall be interpreted as confirmed digital separation.", interpretation: "Unfollowing is a visible digital action that signals relationship change. Because it is publicly observable, it often triggers speculation and social interpretation among mutual connections.", category: "Power Moves", tags: ["Power", "Sociality"], relatableScore: 88, chaoticScore: 70, violatedScore: 80 },
  { id: "60", article: 60, articleTitle: "Conflict Code", section: "60", title: "Remove Follower Regulation", clause: "Removing a follower without unfollowing them shall be considered a silent form of confrontation. This action allows distancing without public visibility and may delay conflict rather than prevent it.", interpretation: "Removing a follower without unfollowing is a subtle and indirect form of conflict. Digital platforms enable passive or hidden forms of confrontation.", category: "Power Moves", tags: ["Power", "Surveillance"], relatableScore: 82, chaoticScore: 75, violatedScore: 65 },
  { id: "61", article: 61, articleTitle: "Conflict Code", section: "61", title: "Block Regulation", clause: "Blocking an individual shall indicate serious conflict, communication breakdown, or intentional digital exclusion. Blocking shall be considered the highest level of digital conflict action. Unblocking does not automatically restore previous digital relations.", interpretation: "Blocking represents the highest level of digital conflict, as it removes all forms of communication, visibility, and interaction. It creates complete digital separation.", category: "Power Moves", tags: ["Power", "Sociality"], relatableScore: 85, chaoticScore: 85, violatedScore: 60 },
  { id: "62", article: 62, articleTitle: "Conflict Code", section: "62", title: "Screenshot Evidence Regulation", clause: "Digital conversations shall be considered permanent and capable of being captured through screenshots. Screenshots may be used as evidence in digital conflicts or social disputes.", interpretation: "Screenshots make digital communication permanent and transferable. Messages can be stored and used as evidence. This creates accountability but also reduces privacy.", category: "Power Moves", tags: ["Surveillance", "Power"], relatableScore: 90, chaoticScore: 80, violatedScore: 75 },
  { id: "63", article: 63, articleTitle: "Conflict Code", section: "63", title: "Reply Behaviour Conflict Regulation", clause: "Sudden changes in reply speed may be interpreted as emotional change, avoidance, or conflict. Intentional delay in response may be used as a conflict strategy or power assertion.", interpretation: "Changes in reply behaviour — such as delays or inconsistency — are often interpreted as signs of emotional change or conflict. Reply timing can be used intentionally as a strategy.", category: "Power Moves", tags: ["Power", "Sociality"], relatableScore: 91, chaoticScore: 60, violatedScore: 82 },
  { id: "64", article: 64, articleTitle: "Conflict Code", section: "64", title: "Dry Reply Conflict Regulation", clause: "Dry replies during serious conversations may escalate conflict. Short replies such as 'ok', 'fine', 'k' may signal anger, disinterest, or unwillingness to communicate. Repeated dry replies may function as silent confrontation.", interpretation: "Dry replies function as a form of indirect conflict where individuals express frustration without openly confronting the issue. Digital communication allows conflict to occur subtly.", category: "Power Moves", tags: ["Power", "Sociality"], relatableScore: 94, chaoticScore: 65, violatedScore: 90 },
  { id: "65", article: 65, articleTitle: "Conflict Code", section: "65", title: "Indirect Conflict Communication Regulation", clause: "Individuals may post indirect messages, quotes, or song lyrics during conflict instead of direct communication. Such posts may be directed at specific individuals while visible to a larger audience.", interpretation: "Indirect posts allow individuals to express conflict without direct confrontation. These messages are often targeted at specific individuals but visible to a wider audience.", category: "Power Moves", tags: ["Power", "Identity"], relatableScore: 87, chaoticScore: 70, violatedScore: 72 },

  // CHAPTER 6 — MEME & INTERNET LANGUAGE CODE
  { id: "66", article: 66, articleTitle: "Meme & Language Code", section: "66", title: "Emoji Language Regulation", clause: "Emojis shall function as indicators of tone, emotion, and intent in digital communication. Absence of emojis in informal communication may be interpreted as seriousness, anger, or emotional distance.", interpretation: "Emojis function as non-verbal cues, replacing facial expressions and tone of voice. Their meaning depends on context, relationship, and platform culture.", category: "Identity & Behaviour", tags: ["Sociality", "Normalisation"], relatableScore: 85, chaoticScore: 40, violatedScore: 55 },
  { id: "67", article: 67, articleTitle: "Meme & Language Code", section: "67", title: "Reaction Image and GIF Regulation", clause: "Reaction images and GIFs shall function as substitutes for verbal responses. Repeated use of reaction images without text may be interpreted as low-effort communication.", interpretation: "Reaction images and GIFs act as substitutes for verbal responses, allowing users to communicate emotions quickly and visually. Digital communication often prioritizes speed and expressiveness.", category: "Identity & Behaviour", tags: ["Sociality", "Normalisation"], relatableScore: 82, chaoticScore: 35, violatedScore: 40 },
  { id: "68", article: 68, articleTitle: "Meme & Language Code", section: "68", title: "Meme Communication Regulation", clause: "Memes shall function as tools for humor, opinion, emotional expression, and relatability. Sharing memes with specific individuals may be interpreted as shared understanding or social closeness.", interpretation: "Memes function as a shared cultural language that communicates humor, opinions, and emotions indirectly. Digital communication is increasingly based on cultural references and relatability.", category: "Identity & Behaviour", tags: ["Sociality", "Identity"], relatableScore: 88, chaoticScore: 40, violatedScore: 30 },
  { id: "69", article: 69, articleTitle: "Meme & Language Code", section: "69", title: "Abbreviation and Short Form Regulation", clause: "Short forms such as 'LOL', 'OMG', 'BRB', 'IDK' shall be used for fast and efficient communication. Excessive use of short replies may reduce emotional clarity and depth.", interpretation: "Abbreviations reduce effort and increase speed, reflecting the fast-paced nature of digital interaction. Digital communication balances efficiency with meaningful expression.", category: "Identity & Behaviour", tags: ["Normalisation", "Sociality"], relatableScore: 78, chaoticScore: 30, violatedScore: 35 },
  { id: "70", article: 70, articleTitle: "Meme & Language Code", section: "70", title: "Slang Language Regulation", clause: "Internet slang shall evolve over time and may differ across digital communities. Use of slang shall indicate digital awareness, cultural participation, and social belonging.", interpretation: "Internet slang evolves within digital communities and reflects cultural participation. Language in digital spaces functions as a marker of identity and group membership.", category: "Identity & Behaviour", tags: ["Identity", "Sociality"], relatableScore: 80, chaoticScore: 35, violatedScore: 40 },
  { id: "71", article: 71, articleTitle: "Meme & Language Code", section: "71", title: "Tone and Text Interpretation Regulation", clause: "Writing in all capital letters shall be interpreted as shouting or strong emotion. Use of full stops in short replies may be interpreted as seriousness, anger, or emotional distance.", interpretation: "Since text lacks vocal tone, users rely on formatting, punctuation, and emojis to convey emotion. Small changes in text style can significantly alter meaning.", category: "Identity & Behaviour", tags: ["Sociality", "Normalisation"], relatableScore: 92, chaoticScore: 50, violatedScore: 70 },
  { id: "72", article: 72, articleTitle: "Meme & Language Code", section: "72", title: "One-Word Reply Regulation", clause: "One-word replies such as 'K', 'Fine', 'Okay', 'Hmm' may be interpreted as conversation closure, annoyance, or low interest. Message tone shall often be interpreted more from style than from literal words.", interpretation: "One-word replies function as strong social signals that can indicate disinterest, annoyance, or conversation closure. In digital communication, message style often conveys more meaning than the actual words used.", category: "Identity & Behaviour", tags: ["Power", "Sociality"], relatableScore: 94, chaoticScore: 55, violatedScore: 88 },
  { id: "73", article: 73, articleTitle: "Meme & Language Code", section: "73", title: "Hashtag and Trend Language Regulation", clause: "Hashtags shall function as tools for content categorization and participation in larger digital conversations. Failure to understand trends may be interpreted as generational distance.", interpretation: "Hashtags and trends allow users to participate in larger digital conversations and increase visibility. Communication in digital spaces is shaped by collective behaviour and viral patterns.", category: "Identity & Behaviour", tags: ["Normalisation", "Identity"], relatableScore: 75, chaoticScore: 30, violatedScore: 35 },
  { id: "74", article: 74, articleTitle: "Meme & Language Code", section: "74", title: "Platform Indicator Language Regulation", clause: "Indicators such as 'Seen', 'Typing…', and 'Online' shall function as non-verbal digital communication. These indicators shall create emotional reactions such as anticipation, anxiety, or reassurance.", interpretation: "Platform indicators function as non-verbal signals that communicate attention and availability. Platform design directly shapes communication behaviour and emotional experience.", category: "Identity & Behaviour", tags: ["Surveillance", "Sociality"], relatableScore: 90, chaoticScore: 55, violatedScore: 60 },
  { id: "75", article: 75, articleTitle: "Meme & Language Code", section: "75", title: "Digital Language Principle", clause: "Digital communication shall consist of text, symbols, images, timing, and platform indicators. Meaning shall be interpreted through context, timing, symbols, and relationship between individuals.", interpretation: "Digital communication is a combination of text, symbols, timing, and platform features. Digital language is complex, multi-layered, and dependent on context and relationships.", category: "Identity & Behaviour", tags: ["Normalisation", "Sociality"], relatableScore: 76, chaoticScore: 25, violatedScore: 30 },

  // PART V — GENERAL PRINCIPLES
  { id: "76", article: 76, articleTitle: "General Principles", section: "76", title: "Visibility Principle", clause: "Digital platforms make user activity visible through features such as read receipts, online status, story views, likes, comments, and activity indicators. Lack of visible response may also be interpreted as a social signal.", interpretation: "Digital platforms transform private actions into visible events. Users become aware that they are being watched, which influences how they act and respond. Visibility turns everyday communication into socially evaluated behaviour.", category: "Power Moves", tags: ["Surveillance", "Power"], relatableScore: 88, chaoticScore: 45, violatedScore: 60 },
  { id: "77", article: 77, articleTitle: "General Principles", section: "77", title: "Permanence Principle", clause: "Digital communication may be stored, recorded, screenshotted, and shared. Deleting messages or content does not guarantee removal of its social impact.", interpretation: "Digital communication is not temporary but persistent and reproducible. Even deleted content continues to exist socially through memory and screenshots.", category: "Power Moves", tags: ["Surveillance", "Power"], relatableScore: 85, chaoticScore: 55, violatedScore: 50 },
  { id: "78", article: 78, articleTitle: "General Principles", section: "78", title: "Interpretation Principle", clause: "Digital actions such as liking, viewing, replying, ignoring, posting, or deleting shall be interpreted as social signals. Absence of action may be interpreted as strongly as presence of action.", interpretation: "In digital spaces, every action — including inaction — carries meaning. Digital communication includes non-verbal indicators like seen receipts and typing signals.", category: "Power Moves", tags: ["Surveillance", "Normalisation"], relatableScore: 90, chaoticScore: 40, violatedScore: 65 },
  { id: "79", article: 79, articleTitle: "General Principles", section: "79", title: "Effort Principle", clause: "The level of effort in digital communication shall reflect the level of relationship importance. Low-effort responses to high-effort communication may be interpreted as disinterest or disrespect.", interpretation: "Effort in digital communication is used to measure the importance of relationships. When effort is not reciprocated, it creates imbalance and perceptions of disinterest or disrespect.", category: "Identity & Behaviour", tags: ["Sociality", "Normalisation"], relatableScore: 91, chaoticScore: 45, violatedScore: 85 },
  { id: "80", article: 80, articleTitle: "General Principles", section: "80", title: "Availability Principle", clause: "Digital presence creates the expectation of communication availability. Being visibly online and not responding may be interpreted as intentional ignoring.", interpretation: "Digital presence creates the expectation of constant availability. Platforms blur the boundary between availability and obligation, creating pressure to respond quickly.", category: "Power Moves", tags: ["Surveillance", "Power"], relatableScore: 89, chaoticScore: 50, violatedScore: 80 },
  { id: "81", article: 81, articleTitle: "General Principles", section: "81", title: "Social Hierarchy Principle", clause: "Digital platforms create visible social hierarchies through followers, likes, comments, views, and Close Friends lists. Access to private stories and personal communication indicates higher social ranking.", interpretation: "Digital platforms structure social relationships into visible hierarchies. These indicators signal levels of closeness, importance, and social ranking.", category: "Power Moves", tags: ["Power", "Identity"], relatableScore: 84, chaoticScore: 40, violatedScore: 55 },
  { id: "82", article: 82, articleTitle: "General Principles", section: "82", title: "Identity Construction Principle", clause: "Individuals present different versions of themselves across different digital platforms. Editing, archiving, and deleting content constitute identity modification.", interpretation: "Digital identity is actively constructed through posts, captions, stories, and interactions. Identity in digital spaces is flexible, controlled, and continuously shaped.", category: "Identity & Behaviour", tags: ["Identity", "Normalisation"], relatableScore: 83, chaoticScore: 35, violatedScore: 45 },
  { id: "83", article: 83, articleTitle: "General Principles", section: "83", title: "Indirect Communication Principle", clause: "Digital platforms allow individuals to communicate indirectly through posts, captions, stories, songs, and status updates. Indirect communication reduces direct confrontation while still conveying messages.", interpretation: "Digital platforms enable users to communicate indirectly. Messages can be directed at specific individuals while remaining visible to a wider audience.", category: "Identity & Behaviour", tags: ["Sociality", "Identity"], relatableScore: 85, chaoticScore: 50, violatedScore: 55 },
  { id: "84", article: 84, articleTitle: "General Principles", section: "84", title: "Audience Principle", clause: "Digital content is often created for a specific audience but may be viewed by a larger unintended audience. Awareness of being watched may influence how individuals present themselves online.", interpretation: "Content created for a specific person or group is often viewed by a much larger audience. Awareness of being watched influences behaviour, leading to more curated communication.", category: "Identity & Behaviour", tags: ["Surveillance", "Identity"], relatableScore: 82, chaoticScore: 35, violatedScore: 45 },
  { id: "85", article: 85, articleTitle: "General Principles", section: "85", title: "Power and Control Principle", clause: "Control over reply time, response tone, and communication frequency may create power imbalance between individuals. The individual who replies less frequently or shows less urgency may hold greater conversational power.", interpretation: "Control over communication creates power dynamics. Individuals who respond less frequently are often perceived as holding more control, while those who respond quickly may appear more emotionally dependent.", category: "Power Moves", tags: ["Power", "Sociality"], relatableScore: 90, chaoticScore: 55, violatedScore: 78 },
];

